using namespace std;

int main(){
    ios::sync_with_stdio(false);
    cin.tie(nullptr);

    int n;
    cin &gt;&gt; n;
    std::unordered_map&lt;int, int&gt; freq;
    std::vector&lt;int&gt; arr(n);
    for (int i = 0; i &lt; n; i++){
        cin &gt;&gt; arr[i];
        freq[arr[i]]++;
    }

    // Extract distinct keys and sort them.
    std::vector&lt;int&gt; keys;
    for (auto &amp;p : freq)
        keys.push_back(p.first);
    sort(keys.begin(), keys.end());

    int ans = 0;
    // For each candidate value v, check if there exists any pair (x, y) with x+y = 2*v.
    for (auto v : keys) {
        int target = 2 * v;
        bool found = false;
        for (auto x : keys) {
            int y = target - x;
            if (freq.find(y) != freq.end()){
                // If x equals y, there must be at least two occurrences.
                if (x == y &amp;&amp; freq[x] &lt; 2)
                    continue;
                found = true;
                break;
            }
        }
        if(found)
            ans += freq[v];
    }
    cout &lt;&lt; ans &lt;&lt; "\n";
    return 0;
}
